/// <reference path="../typings/index.d.ts" />
import {BeSkill} from '@be/be-framework';
import jibo = require('jibo');

const mainFlow: any = require('./flows/main');

class MainMenu extends BeSkill {

    public flow: jibo.flow.FlowExecutor = null;
    // flag set the next skill is chosen, prevents new skills from possibly interferring
    public skillChosen: boolean = false;
    //for unit tests
    private flowOverrides:any = null;

    /**
     * MainMenu skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack) {
        super(assetPack);
    }

    /**
     * Start the skill, this opens the main menu view.
     */
    public open(result?: any, refresh?: boolean, previousSkillName?: string, previousSkillOptions?: any) {
        if (!refresh) {
            //if we were launched via tap, then make menus listen-less
            if (result && result.intent === 'tap') {
                jibo.mim.silentMenus = true;
                //syslogs & analytics so we can determine menu usage
                this.log.info('open() from tap');
                this.track('Menu Opened', {modality: 'touch'});
            } else if (result && result.asr.text) {
                this.log.info('open() from HJ/global');
                this.track('Menu Opened', {modality: 'voice'});
            } else {
                this.log.info('open() from other skill');
                this.track('Menu Opened', {modality: 'return'});
            }

            this.skillChosen = false;
            const options = Object.assign({
                assetPack: this.assetPack,
                enableLogging: true,
                blackboard: {
                    log: this.log,
                    skill: this
                }
            },
                this.flowOverrides
            );
            this.flow = jibo.flow.run(
                mainFlow,
                options,
                (err, status) => {
                    this.log.debug('flow ended with status',status);
                    if (status !== jibo.bt.Status.INTERRUPTED) {
                        this.log.debug('flow ended without interruption');
                        this.flow.destroy();
                        this.flow = null;
                        this.exit();
                    }
                    else{
                        this.log.debug('flow ended with interruption, skill chosen',this.skillChosen);
                    }
                }
            );
        }
        else {
            this.log.info('open() refresh');
            // emit No Global to tell any menu mims that were open
            // to keep listening, since relaunches interrupt them.
            jibo.globalEvents.shared.nonInterruptingGlobal.emit();

            // if we are "reentering" the main menu, tell the user that we're
            // already on it
            let alreadyOnMenuMimConfig: any = {
                mimPath: 'mims/en-us/AlreadyOnMenu.mim',
                assetPack: this.assetPack
            };

            let alreadyOnMenuMim = new jibo.bt.behaviors.Mim(alreadyOnMenuMimConfig);
            alreadyOnMenuMim.start();
        }
    }

    /**
     * Opens the skill that matches the given intent.
     * @method openSkill
     * @param {string} intent - Name of the skill to open
     */
    public redirectToSkill(skill: string):boolean {
        this.log.debug('redirectToSkill() given skill: ' + skill);
        if(this.skillChosen || !skill){
            this.log.warn('redirectToSkill() attempt to skill: ' + skill + ' but a skill has already been chosen.');
            return;
        }
        if (skill === 'fun' || skill === 'personal-report') {
            // do nothing
            return false;
        }
        let redirectOptions: any;
        //Cloud skills should be launched by faking a global turn with our NLU result
        // handle chit-chat skills
        let isCloud = false;

        if (skill === 'joke') {
            isCloud = true;
            skill = 'chitchat';
            redirectOptions = {
                clientASR: 'tell me a joke'
            };
        }
        else if (skill === 'dance') {
            isCloud = true;
            skill = 'chitchat';
            redirectOptions = {
                clientASR: 'do a dance'
            };
        }
        else if (skill === 'surprise'){
            isCloud = true;
            skill = 'chitchat';
            redirectOptions = {
                clientASR: 'surprise me'
            };
        }
        else if(skill === 'full-report'){
            isCloud = true;
            skill = 'personal-report';
            redirectOptions = {
                clientASR: 'personal report'
            };
        }
        else if(skill === 'weather'){
            isCloud = true;
            skill = 'personal-report';
            redirectOptions = {
                clientASR: 'tell me about the weather'
            };
        }
        else if(skill === 'news'){
            isCloud = true;
            skill = 'personal-report';
            redirectOptions = {
                clientASR: 'tell me about the news'
            };
        }
        else if(skill === 'calendar'){
            isCloud = true;
            skill = 'personal-report';
            redirectOptions = {
                clientASR: 'tell me about my calendar'
            };
        }
        else if(skill === 'commute'){
            isCloud = true;
            skill = 'personal-report';
            redirectOptions = {
                clientASR: 'what does my commute look like'
            };
        }
        // check for create's subskills
        else {
            let intent: string;
            if (skill === 'photobooth') {
                intent = 'createSomePhotos';
                skill = 'create';
            }
            else if (skill === 'snapshot') {
                intent = 'createOnePhoto';
                skill = 'create';
            }
            else {
                intent = 'menu';
            }
            redirectOptions = {
                nlu: {
                    entities: {
                        domain: skill,
                    },
                    intent: intent
                }
            };
        }

        this.skillChosen = true;
        jibo.face.views.changeView(
            {
                remove: true,
                leaveEmpty: true,
                transitionClose: jibo.face.views.TRANSITION.UP
            },
            () => {
                //only redirect after the change view if it is a local skill
                if (!isCloud) {
                    this.redirect(`@be/${skill}`, redirectOptions);
                }
            }
        );
        //if cloud skill, send the launch in parallel to save time
        if (isCloud) {
            jibo.embodied.listen.disableOnce();
            jibo.jetstream.mimicGlobalTurn(redirectOptions).catch((err) => {
                this.log.error(`Unable to mimic global turn to launch cloud skill ${skill} with data`, redirectOptions, err);
                this.exit();
            });
        }
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    public close(done: () => void): void {
        this.log.info('close()');

        // if flow still exists, destroy active flow & close views
        if (this.flow) {
            this.log.info('close() flow requires stop and destroy followed by view clean up');
            Promise.all([
                //stop the main flow
                this.flow.stop()
                .catch((err) => {
                    this.log.error('Error when stopping flow: ', err);
                })
                .then(() => {
                    this.flow.destroy();
                    this.flow = null;
                }),

                //clean up views
                this.cleanupViews()
                .catch((err) => {
                    this.log.debug('Eror when closing views: ', err);
                })
            ]).then(() => {
                done();
            });
        } else {
            this.cleanupViews()
            .then(done);
        }
    }

    /**
     * Clean up views.
     * If a skill was chosen then views should already be closed and current view empty,
     * if currentView is not empty there was a problem and we close views
     */
    public cleanupViews(): Promise<void> {
      return new Promise<void>((resolve) => {
        jibo.face.views.viewStackCleanup()
        .then(()=> {
          resolve();
        })
        .catch(()=> {
          this.log.debug('cleanupViews() failed to remove all views, calling done anyway');
          resolve();
        });
      });
    }
}

module.exports = MainMenu;
